// 排版表格：表名黑体小五号居中，表格与页面等宽，跨页重复表头，表头黑体五号居中加粗，表格内容宋体五号靠左对齐
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var tableCount = tables.Count;

for (var i = 1; i <= tableCount; i++) {
    var table = tables.Item(i);

    // 设置表格宽度与页面等宽
    var pageWidth = doc.PageSetup.PageWidth - doc.PageSetup.LeftMargin - doc.PageSetup.RightMargin;
    table.PreferredWidthType = 1; // wdPreferredWidthPercent
    table.PreferredWidth = 100;

    // 设置跨页重复表头
    if (table.Rows.Count > 1) {
        var headerRow = table.Rows.Item(1);
        headerRow.HeadingFormat = true;
    }

    // 设置表头格式（第一行）
    if (table.Rows.Count >= 1) {
        var headerRow = table.Rows.Item(1);
        var headerRange = headerRow.Range;
        headerRange.Font.Name = "黑体";
        headerRange.Font.Size = 10.5; // 五号
        headerRange.Font.Bold = true;
        headerRange.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter

        // 遍历表头每个单元格
        for (var j = 1; j <= headerRow.Cells.Count; j++) {
            var cell = headerRow.Cells.Item(j);
            cell.Range.ParagraphFormat.Alignment = 1; // 居中
        }
    }

    // 设置表格内容格式（除表头外的行）
    for (var r = 2; r <= table.Rows.Count; r++) {
        var row = table.Rows.Item(r);
        var rowRange = row.Range;
        rowRange.Font.Name = "宋体";
        rowRange.Font.Size = 10.5; // 五号
        rowRange.Font.Bold = false;

        // 遍历该行每个单元格，设置靠左对齐
        for (var c = 1; c <= row.Cells.Count; c++) {
            var cell = row.Cells.Item(c);
            cell.Range.ParagraphFormat.Alignment = 0; // wdAlignParagraphLeft
        }
    }
}

// 处理表名段落（查找包含"表"字的段落并应用格式）
var paragraphs = doc.Paragraphs;
for (var p = 1; p <= paragraphs.Count; p++) {
    var para = paragraphs.Item(p);
    var text = para.Range.Text;
    // 匹配表名：以"表"开头或包含"表 X"格式
    if (text.indexOf("表") === 0 || /表\s*\d+/.test(text)) {
        para.Range.Font.Name = "黑体";
        para.Range.Font.Size = 9; // 小五号
        para.Range.Font.Bold = true;
        para.Range.ParagraphFormat.Alignment = 1; // 居中
    }
}

return "表格排版完成，共处理 " + tableCount + " 个表格";
